# Write a program that calculates how many multiplication is done by the Miller-Rabin primality test for a given p and a base!
def mr_mul_count(p:int, a: int) -> int:
    if p <= 2 or p % 2 == 0:
        return 0

    d = p - 1
    s = 0
    while d % 2 == 0:
        s += 1
        d //= 2

    muls = 0
    r = a

    bits = bin(d)[3:]
    for b in bits:
        r = (r * r) % p
        muls += 1
        
        if b == '1':
            r = (r * a) % p
            muls += 1

    if r == 1 or r == p - 1:
        return muls

    for _ in range(s):
        r = (r * r) % p
        muls += 1

        if r == p - 1 or r == 1:
            break

    return muls

